sql:
SELECT students.name, attendance.percentage
FROM students
INNER JOIN attendance ON students.roll = attendance.roll;

external_knowledge:
- "prodigies named John": Students whose names start with "John";
- "navigating the vast oceans of Computer Science knowledge": Students enrolled in Computer Science courses;
- "navigation details of their academic journey": Details including roll number, name, email, contact number, date of birth, program, admission year, semester, and course name;
- "presence voyage": Number of days present;
- "tutor’s lighthouse guides": Faculty member's name, email, and contact number;
- "stormy days they've braved": Number of days absent.

sql:
SELECT s.*
FROM students s
JOIN attendance a ON s.roll = a.roll
WHERE a.percentage = (
    SELECT MAX(percentage) FROM attendance
);

SELECT AVG(percentage) AS average_attendance_percentage
FROM attendance
WHERE course_id = (SELECT course_id FROM courses WHERE course_name = 'Operating System');

external_knowledge:
- Underperforming students refer to students with an attendance percentage below 70%;
- The upcoming spring term refers to the Spring semester of the academic year 2023-2024;
- The specific course refers to the course with an ID of 1.
